const body = $input.first().json.body || $input.first().json;

// LibreNMS alert payload fields
const title    = body.title    || body.rule    || 'Alert';
const host     = body.hostname || body.host    || 'unknown host';
const severity = body.severity || 'unknown';
const message  = body.message  || body.body    || '';
const state    = body.state;  // 1=alert, 0=recovery

const emoji    = state === 0 ? '✅' : (severity === 'critical' ? '🔴' : '🟡');
const stateStr = state === 0 ? 'RESOLVED' : 'FIRING';

const discord_message = [
  `${emoji} **LibreNMS ${stateStr}** — ${title}`,
  `**Host:** ${host}`,
  `**Severity:** ${severity}`,
  message ? `**Detail:** ${message}` : null
].filter(Boolean).join('\n');

return [{ json: { discord_message, severity, state } }];
